import{_ as a,c as s,o as i,aj as t}from"./chunks/framework.guNMSiFm.js";const k=JSON.parse('{"title":"Running Iroha on Bare Metal","description":"","frontmatter":{},"headers":[],"relativePath":"guide/advanced/running-iroha-on-bare-metal.md","filePath":"guide/advanced/running-iroha-on-bare-metal.md","lastUpdated":1777621302000}'),n={name:"guide/advanced/running-iroha-on-bare-metal.md"};function r(l,e,o,h,p,d){return i(),s("div",null,[...e[0]||(e[0]=[t(`<h1 id="running-iroha-on-bare-metal" tabindex="-1">Running Iroha on Bare Metal <a class="header-anchor" href="#running-iroha-on-bare-metal" aria-label="Permalink to &quot;Running Iroha on Bare Metal&quot;">​</a></h1><p>Use this workflow when you want to run peers directly on hosts instead of through Docker Compose. The current source tree provides Kagami generators that write matching genesis, peer configs, client config, and start/stop scripts.</p><h2 id="_1-build-the-binaries" tabindex="-1">1. Build the Binaries <a class="header-anchor" href="#_1-build-the-binaries" aria-label="Permalink to &quot;1. Build the Binaries&quot;">​</a></h2><p>From the upstream Iroha workspace:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">cargo</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> build</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --release</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -p</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> irohad</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -p</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> iroha_cli</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -p</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> iroha_kagami</span></span></code></pre></div><p>This produces:</p><ul><li><code>target/release/irohad</code> for the peer daemon</li><li><code>target/release/iroha</code> for the CLI</li><li><code>target/release/kagami</code> for key, genesis, and localnet generation</li></ul><p>The same workspace also builds <code>iroha2</code>/<code>iroha2d</code> and <code>iroha3</code>/<code>iroha3d</code> aliases when scripts need to make the selected track explicit.</p><h2 id="_2-generate-a-local-network" tabindex="-1">2. Generate a Local Network <a class="header-anchor" href="#_2-generate-a-local-network" aria-label="Permalink to &quot;2. Generate a Local Network&quot;">​</a></h2><p>Generate a four-peer Iroha 3 localnet:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">target/release/kagami</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> localnet</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --build-line</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> iroha3</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --peers</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> 4</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --out-dir</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> ./localnet</span></span></code></pre></div><p>For an Iroha 2-style localnet, set the build line explicitly:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">target/release/kagami</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> localnet</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --build-line</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> iroha2</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --peers</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> 4</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --out-dir</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> ./localnet-iroha2</span></span></code></pre></div><p>The output directory contains the generated <code>genesis.json</code>, <code>genesis.signed.nrt</code>, peer <code>config.toml</code> files, <code>client.toml</code>, helper scripts, and a generated <code>README.md</code> with exact commands for that bundle.</p><h2 id="_3-start-peers" tabindex="-1">3. Start Peers <a class="header-anchor" href="#_3-start-peers" aria-label="Permalink to &quot;3. Start Peers&quot;">​</a></h2><p>For a generated disposable localnet, use the generated script:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">./localnet/start.sh</span></span></code></pre></div><p>If you need to wire each peer into a process manager such as systemd, use the launch command recorded in <code>./localnet/README.md</code> for each peer. Keep each peer&#39;s <code>config.toml</code>, private key, storage directory, and ports separate.</p><h2 id="_4-operate-the-network" tabindex="-1">4. Operate the Network <a class="header-anchor" href="#_4-operate-the-network" aria-label="Permalink to &quot;4. Operate the Network&quot;">​</a></h2><p>Use the generated client config:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">target/release/iroha</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --config</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> ./localnet/client.toml</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> ledger</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> domain</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> list</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> all</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">target/release/iroha</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --config</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> ./localnet/client.toml</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --output-format</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> text</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> ops</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> sumeragi</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> status</span></span></code></pre></div><p>Stop the generated localnet with:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">./localnet/stop.sh</span></span></code></pre></div><h2 id="_5-production-notes" tabindex="-1">5. Production Notes <a class="header-anchor" href="#_5-production-notes" aria-label="Permalink to &quot;5. Production Notes&quot;">​</a></h2><ul><li>Generate fresh private keys for production and store them outside the repository.</li><li>Make every peer agree on the same signed genesis transaction, topology, trusted peers, and validator PoPs.</li><li>Bind listener addresses to host-local interfaces only when the peer should not be reachable from other machines.</li><li>Use a reverse proxy or firewall for Torii exposure, basic auth, TLS, and rate limiting.</li><li>Treat changes to genesis or consensus topology as coordinated migrations, not single-peer file edits.</li></ul><p>For containerized local development, use the <a href="./../../get-started/launch-iroha-2.html">Launch Iroha 3</a> Docker Compose workflow.</p>`,26)])])}const g=a(n,[["render",r]]);export{k as __pageData,g as default};
